+    // ── Cross-thread with err ─────────────────────────────────
+
+    #[test]
+    fn promise_err_from_another_thread() {
+        let mut p: Promise<i32> = Promise::new();
+        let mut fut = p.get_future().unwrap();
+
+        let handle = std::thread::spawn(move || {
+            p.err(anyhow::anyhow!("thread error"));
+        });
