+        match StdFuture::poll(Pin::new(&mut fut), &mut cx) {
+            Poll::Ready(Err(e)) => assert_eq!(e.to_string(), "thread error"),
+            other => panic!("{}", format!("expected Ready(Err), got {other:?}")),
+        }
+    }
